from pathlib import Path
import re
files=[p for p in Path('docs').rglob('*.md')]+[Path('README.md')]
missing=[]
pat=re.compile(r'\[[^\]]*\]\(([^)]+)\)')
for p in files:
    for m in pat.finditer(p.read_text(errors='ignore')):
        raw=m.group(1).split()[0].strip('<>')
        if not raw or re.match(r'^[a-zA-Z][a-zA-Z0-9+.-]*:',raw) or raw.startswith('#') or raw.startswith('mailto:'):
            continue
        path=raw.split('#')[0]
        if not path or '&' in path or '<' in path or '>' in path or ('.' not in path and '/' not in path):
            continue
        target=(p.parent/path).resolve()
        try: rel=target.relative_to(Path.cwd().resolve())
        except ValueError: continue
        if not (str(rel).startswith('docs/') or (p==Path('README.md') and path.startswith('docs/'))):
            continue
        if not target.exists(): missing.append((str(p), raw, str(rel)))
if missing:
    for x in missing: print(x)
    raise SystemExit(1)
print('docs internal markdown links ok')
PY
